from flask import Flask, jsonify, request
import os
import json
import time

app = Flask(__name__)
CACHE_DIR = 'cache'
CACHE_EXPIRATION = 3600  # 1 hour in seconds

def create_cache_dir():
    if not os.path.exists(CACHE_DIR):
        os.makedirs(CACHE_DIR)

def get_cache_key(url, params):
    key = url + '?' + '&'.join([f"{k}={v}" for k, v in sorted(params.items())])
    return key.replace('/', '_').replace('?', '_')

def load_from_cache(key):
    cache_file = os.path.join(CACHE_DIR, f'{key}.json')
    if os.path.exists(cache_file) and (time.time() - os.path.getmtime(cache_file)) < CACHE_EXPIRATION:
        with open(cache_file, 'r') as file:
            return json.load(file)
    return None

def save_to_cache(key, data):
    cache_file = os.path.join(CACHE_DIR, f'{key}.json')
    with open(cache_file, 'w') as file:
        json.dump(data, file)

@app.route('/api', methods=['GET'])
def api():
    url = request.args.get('url')
    params = dict(request.args.items())
    key = get_cache_key(url, params)
    
    response_data = load_from_cache(key)
    if response_data is None:
        # Simulate an expensive API call
        response_data = {
            'data': {'key': 'value', 'nested': {'subkey': 'subvalue'}},
            'metadata': {'timestamp': time.time()}
        }
        save_to_cache(key, response_data)
    
    return jsonify(response_data)

if __name__ == '__main__':
    create_cache_dir()
    app.run(debug=True)